import (
	"container/heap"
	"math"
)

type Edge struct {
	to     int
	cost   int64
	minCost int64
}

type Path struct {
	node    int
	total   int64
	minEdge int64
}

type MinHeap []Path

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i].total < h[j].total }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x interface{}) {
	*h = append(*h, x.(Path))
}
func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	graph := make([][]Edge, n)
	for _, e := range edges {
		u, v, cost := e[0], e[1], e[2]
		if u == v {
			continue
		}
		graph[u] = append(graph[u], Edge{to: int(v), cost: cost})
	}

	maxMin := int64(-1)
	pq := &MinHeap{}
	heap.Init(pq)
	heap.Push(pq, Path{node: 0, total: 0, minEdge: math.MaxInt64})

	for pq.Len() > 0 {
		current := heap.Pop(pq).(Path)
		node := current.node
		total := current.total
		minEdge := current.minEdge

		if node == n-1 {
			if total <= k {
				if minEdge != math.MaxInt64 && minEdge > maxMin {
					maxMin = minEdge
				}
			}
			continue
		}

		if total > k {
			continue
		}

		for _, edge := range graph[node] {
			if !online[edge.to] && edge.to != n-1 {
				continue
			}
			newTotal := total + edge.cost
			newMin := minEdge
			if edge.cost < newMin {
				newMin = edge.cost
			}
			if newTotal <= k {
				heap.Push(pq, Path{node: edge.to, total: newTotal, minEdge: newMin})
			}
		}
	}

	return maxMin
}
