	graph := make([][]Edge, n)
	for _, e := range edges {
		u, v, cost := int(e[0]), int(e[1]), e[2]
		graph[u] = append(graph[u], Edge{to: v, cost: cost})
	}

	maxMin := int64(-1)
	visited := make([]map[int64]int64, n) // visited[node][total] = max minEdge for that total
	for i := range visited {
		visited[i] = make(map[int64]int64)
	}

	h := &MinHeap{}
	heap.Init(h)
	heap.Push(h, Path{node: 0, total: 0, minEdge: math.MaxInt64})

